3885: /// Run the full inference engine + concurrency lint over the bridged graph.
3886: ///
3887: /// * missing-guard mining and unsanitized-flow taint run over the call/dataflow
3888: ///   graph (no source needed);
3889: /// * the concurrency lint re-parses each distinct on-disk source file (only
3890: ///   Rust is wired in the walker today).
3891: ///
3892: /// Findings below `min_confidence` are dropped (concurrency findings are
3893: /// high-precision and assigned a fixed 0.9). Sorted by confidence descending.
3894: pub fn vuln_report(
3895:     graph: &AnalysisGraph,
3896:     workspace_root: &Path,
3897:     min_confidence: f64,
3898: ) -> VulnReport {
3899:     let mut findings: Vec<VulnFindingOut> = Vec::new();
3900: 
3901:     // 1. Missing-guard deviation (BAC / IDOR), inferred from corpus consistency.
3902:     let guard_findings = mine_missing_guards(graph, &MineConfig::default());
3903:     let missing_guard_count = guard_findings.len();
3904:     for f in guard_findings {
3905:         let (file, line, symbol) = render_site(graph, &f.site);
3906:         findings.push(VulnFindingOut {
3907:             kind: f.template.id().to_owned(),
3908:             class: f.class,
3909:             origin: f.origin.id().to_owned(),
3910:             file,
3911:             line,
3912:             symbol,
3913:             confidence: f.confidence,
3914:             message: f.message,
3915:         });
3916:     }
3917: 
3918:     // 2. Unsanitized taint flows (IDOR / SSRF / injection), inferred seeds.
3919:     let taint_findings = scan_unsanitized_flows(graph, &[]);
3920:     let taint_count = taint_findings.len();
3921:     for f in taint_findings {
3922:         let (file, line, symbol) = render_site(graph, &f.site);
3923:         findings.push(VulnFindingOut {
3924:             kind: f.template.id().to_owned(),
3925:             class: f.class,
3926:             origin: f.origin.id().to_owned(),
3927:             file,
3928:             line,
3929:             symbol,
3930:             confidence: f.confidence,
3931:             message: f.message,
3932:         });
3933:     }
3934: 
3935:     // 3. Concurrency / control-plane lint over distinct on-disk source files.
3936:     let mut seen_files: HashSet<PathBuf> = HashSet::new();
3937:     for func in graph.nodes_by_kind(ANodeKind::Function) {
3938:         seen_files.insert(func.file_path.clone());
3939:     }
3940:     let mut concurrency_count = 0usize;
3941:     let mut files: Vec<PathBuf> = seen_files.into_iter().collect();
3942:     files.sort();
3943:     for rel in files {
3944:         let lang = match rel.extension().and_then(|e| e.to_str()) {
3945:             Some("rs") => "rust",
3946:             _ => continue,
3947:         };
3948:         let Ok(source) = std::fs::read_to_string(workspace_root.join(&rel)) else {
3949:             continue;
3950:         };
3951:         for c in concurrency::analyze_source(lang, &source) {
3952:             concurrency_count += 1;
3953:             findings.push(VulnFindingOut {
3954:                 kind: c.rule.id().to_owned(),
3955:                 class: None,
3956:                 origin: "concurrency".to_owned(),
3957:                 file: rel.to_string_lossy().into_owned(),
3958:                 line: c.line as u32,
3959:                 symbol: c.function.unwrap_or_else(|| "<module>".to_owned()),
3960:                 confidence: 0.9,
3961:                 message: c.message,
3962:             });
3963:         }
3964:     }
3965: 
3966:     let scanned_functions = graph.nodes_by_kind(ANodeKind::Function).len();
3967:     // Test code dominates false positives (fixtures named `test_*`, `tests/`
3968:     // helpers reaching `open`/`remove`); drop it from a security scan.
3969:     findings.retain(|f| !is_test_site(&f.file, &f.symbol));
3970:     // A missing-guard deviation is only a *security* finding when the inferred
3971:     // guard reads like a security control (auth/validation → a class label).
3972:     // Deviations around benign helpers (`new`, `default`, `builder`) are real
3973:     // structural variation, not vulnerabilities — keep them out of a vuln scan.
3974:     // Discovery stays rule-free; the label only decides security relevance.
3975:     findings.retain(|f| f.kind != "missing_dominator_check" || f.class.is_some());
3976:     findings.retain(|f| f.confidence >= min_confidence);
3977:     findings.sort_by(|a, b| {
3978:         b.confidence
3979:             .partial_cmp(&a.confidence)
3980:             .unwrap_or(std::cmp::Ordering::Equal)
3981:             .then_with(|| a.file.cmp(&b.file))
3982:             .then_with(|| a.line.cmp(&b.line))
3983:     });
3984: 
3985:     VulnReport {
3986:         findings,
3987:         missing_guard_count,
3988:         taint_count,]

