59: /// Verifies role proposals against graph facts before they are trusted.
60: pub struct GraphVerifier<'a> {
61:     pub graph: &'a CodeGraph,
62:     /// A proposed sink must have at least this many distinct callers to be a
63:     /// believable "called from many places" sink.
64:     pub min_callers: usize,
65: }
